import { Suspense } from 'react';
import { Target, Trophy, Flame, Clock, Star } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import Link from 'next/link';

export const metadata = {
  title: 'Desafios | Nipo School',
  description: 'Participe de desafios e ganhe pontos e conquistas',
};

// Mock data
const stats = {
  submetidos: 8,
  aprovados: 5,
  pontosGanhos: 450,
};

const desafios = [
  {
    id: '1',
    titulo: 'Domínio da Escala Maior',
    descricao: 'Toque todas as escalas maiores sem erros em diferentes tonalidades',
    dificuldade: 'medio',
    pontos: 100,
    prazo: '2024-12-31',
    status: 'ativo',
    participantes: 24,
  },
  {
    id: '2',
    titulo: 'Sight Reading Challenge',
    descricao: 'Leia e toque uma peça à primeira vista com precisão mínima de 90%',
    dificuldade: 'dificil',
    pontos: 200,
    prazo: '2024-12-25',
    status: 'ativo',
    participantes: 12,
  },
  {
    id: '3',
    titulo: 'Primeira Performance',
    descricao: 'Grave e envie sua primeira apresentação musical completa',
    dificuldade: 'facil',
    pontos: 50,
    prazo: '2024-12-20',
    status: 'concluido',
    participantes: 45,
  },
  {
    id: '4',
    titulo: 'Teoria Musical Avançada',
    descricao: 'Complete o quiz de teoria musical com 100% de acertos',
    dificuldade: 'dificil',
    pontos: 150,
    prazo: '2025-01-15',
    status: 'ativo',
    participantes: 18,
  },
];

function getDificuldadeColor(dificuldade: string) {
  const colors = {
    facil: 'bg-green-100 text-green-800 border-green-200',
    medio: 'bg-yellow-100 text-yellow-800 border-yellow-200',
    dificil: 'bg-red-100 text-red-800 border-red-200',
  };
  return colors[dificuldade as keyof typeof colors] || colors.facil;
}

function getDificuldadeLabel(dificuldade: string) {
  const labels = {
    facil: 'Fácil',
    medio: 'Médio',
    dificil: 'Difícil',
  };
  return labels[dificuldade as keyof typeof labels] || dificuldade;
}

function getStatusColor(status: string) {
  const colors = {
    ativo: 'bg-blue-100 text-blue-800 border-blue-200',
    concluido: 'bg-green-100 text-green-800 border-green-200',
    expirado: 'bg-gray-100 text-gray-800 border-gray-200',
  };
  return colors[status as keyof typeof colors] || colors.ativo;
}

function DesafiosContent() {
  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
          <Target className="w-8 h-8 text-orange-600" />
          Desafios
        </h1>
        <p className="text-gray-600 mt-2">
          Participe de desafios e ganhe pontos e conquistas
        </p>
      </div>

      {/* Estatísticas */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card className="bg-gradient-to-br from-blue-50 to-blue-100 border-blue-200">
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-blue-700 font-medium">Desafios Submetidos</p>
                <p className="text-3xl font-bold text-blue-900">{stats.submetidos}</p>
              </div>
              <Trophy className="text-blue-600" size={40} />
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-green-50 to-green-100 border-green-200">
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-green-700 font-medium">Aprovados</p>
                <p className="text-3xl font-bold text-green-900">{stats.aprovados}</p>
              </div>
              <Target className="text-green-600" size={40} />
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-purple-50 to-purple-100 border-purple-200">
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-purple-700 font-medium">Pontos Ganhos</p>
                <p className="text-3xl font-bold text-purple-900">{stats.pontosGanhos}</p>
              </div>
              <Star className="text-purple-600" size={40} />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Lista de Desafios */}
      <div className="grid gap-4">
        {desafios.map((desafio) => (
          <Card key={desafio.id} className="hover:shadow-lg transition-shadow">
            <CardHeader>
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-2">
                    <CardTitle className="text-xl">{desafio.titulo}</CardTitle>
                    <Badge className={getDificuldadeColor(desafio.dificuldade)}>
                      {getDificuldadeLabel(desafio.dificuldade)}
                    </Badge>
                    {desafio.status === 'concluido' && (
                      <Badge className={getStatusColor(desafio.status)}>
                        ✓ Concluído
                      </Badge>
                    )}
                  </div>
                  <CardDescription>{desafio.descricao}</CardDescription>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {/* Metadata */}
                <div className="flex items-center gap-6 text-sm text-gray-600">
                  <div className="flex items-center gap-2">
                    <Trophy className="w-4 h-4 text-yellow-600" />
                    <span className="font-medium text-yellow-700">+{desafio.pontos} pontos</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Clock className="w-4 h-4 text-blue-600" />
                    <span>Prazo: {new Date(desafio.prazo).toLocaleDateString('pt-BR')}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Target className="w-4 h-4 text-green-600" />
                    <span>{desafio.participantes} participantes</span>
                  </div>
                </div>

                {/* Actions */}
                <div className="flex gap-2">
                  {desafio.status === 'ativo' ? (
                    <Button asChild className="bg-gradient-to-r from-orange-600 to-red-600 hover:from-orange-700 hover:to-red-700">
                      <Link href={`/alunos/desafios/${desafio.id}`}>
                        <Flame className="w-4 h-4 mr-2" />
                        Participar
                      </Link>
                    </Button>
                  ) : (
                    <Button asChild variant="outline">
                      <Link href={`/alunos/desafios/${desafio.id}`}>
                        Ver Detalhes
                      </Link>
                    </Button>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Empty State */}
      {desafios.length === 0 && (
        <Card className="p-12 text-center">
          <Target className="w-16 h-16 mx-auto mb-4 text-gray-400" />
          <h3 className="text-xl font-semibold text-gray-900 mb-2">
            Nenhum desafio disponível no momento
          </h3>
          <p className="text-gray-600">
            Fique atento! Novos desafios são publicados regularmente
          </p>
        </Card>
      )}
    </div>
  );
}

export default function DesafiosPage() {
  return (
    <Suspense fallback={<div className="p-8">Carregando desafios...</div>}>
      <DesafiosContent />
    </Suspense>
  );
}
